(21, 1734, 'Assinale a alternativa que apresenta a melhor conceituação do termo meio ambiente:', 'É a inter-relação entre os diversos componentes físicos e humanos.', 'É a junção somente dos aspectos naturais do espaço geográfico.', 'É constituído apenas por elementos que fazem parte da natureza.', 'É a relação entre os aspectos de origem antrópica do espaço social.', 'sem_imagem.png', NULL, NULL, '', '', NULL, '', '', NULL, NULL, 1),
(21, 1735, 'Assinale a alternativa que NÃO apresenta um problema ambiental:', 'Infiltração da água da chuva no solo.', 'Caça de diversos animais silvestres.', 'Retirada da vegetação nativa local.', 'Desflorestamento de matas nativas.', 'sem_imagem.png', NULL, NULL, '', '', NULL, '', '', NULL, NULL, 1),
(21, 1736, 'Qual conceito ligado ao meio ambiente defende a manutenção das características naturais do espaço natural, ou seja, sem nenhum tipo de intervenção antrópica?', 'Preservação ambiental.', 'Conservação ambiental.', 'Desenvolvimento natural.', 'Reserva sustentável', 'sem_imagem.png', NULL, NULL, '', '', NULL, '', '', NULL, NULL, 1),
(21, 1737, 'O conceito de conservação ambiental implica no uso racional dos recursos naturais. Desse modo, ele está diretamente ligado ao conceito de', 'sustentabilidade.', 'preservação.', 'meio natural.', 'comunidade.', 'sem_imagem.png', NULL, NULL, '', '', NULL, '', '', NULL, NULL, 1),
(21, 1738, 'Qual foi a primeira grande conferência internacional, realizada pela Organização das Nações Unidas (ONU), sobre o meio ambiente em nível global?', 'Conferência das Nações Unidas sobre o Meio Ambiente Humano.', 'Conferência das Nações Unidas para o Meio Ambiente e o Desenvolvimento.', 'Conferência das Nações Unidas sobre Mudanças Climáticas.', 'Conferência das Nações Unidas sobre Desenvolvimento Sustentável', 'sem_imagem.png', NULL, NULL, '', '', NULL, '', '', NULL, NULL, 1),
(21, 1739, 'Qual o nome do acordo, realizado por meio da Conferência das Nações Unidas sobre Mudanças Climáticas do ano de 2015, que estabeleceu medidas de controle do aquecimento global?', 'Acordo de Paris.', 'Acordo de Kyoto.', 'Acordo de Montreal.', 'Acordo de Londres.', 'sem_imagem.png', NULL, NULL, '', '', NULL, '', '', NULL, NULL, 1),
(21, 1740, 'Como é corretamente denominado o sistema ambiental caracterizado pelo conjunto de relações estabelecidas entre uma comunidade e o meio ambiente?', 'Ecossistema.', 'População.', 'Habitat.', 'Natureza.', 'sem_imagem.png', NULL, NULL, '', '', NULL, '', '', NULL, NULL, 1),
(21, 1741, 'Assinale a alternativa que apresenta uma característica do espaço ambiental brasileiro:', 'Ocorrência de graves impactos ambientais no meio natural.', 'Existência de uma pequena quantidade de espécies vegetais.', 'Diminuto volume de espécies consideradas endêmicas.', 'Presença de grandes espaços naturais bastante homogêneos.', 'sem_imagem.png', NULL, NULL, '', '', NULL, '', '', NULL, NULL, 1);
INSERT INTO `pergunta2` (`idtema`, `id`, `pergunta`, `respcerta`, `resp2`, `resp3`, `resp4`, `caminhoimagem`, `caract_proposta`, `analise_proposta`, `analise_gpt`, `analise_gemini`, `origem_analise`, `fala_gpt`, `fala_gemini`, `origem_fala`, `fala_proposta`, `publica`) VALUES
(21, 1742, '(Enem 2007) Devido ao aquecimento global e à consequente diminuição da cobertura de gelo no Ártico, aumenta a distância que os ursos polares precisam nadar para encontrar alimentos. Apesar de exímios nadadores, eles acabam morrendo afogados devido ao cansaço. A situação descrita acima', 'alerta para prejuízos que o aquecimento global pode acarretar à biodiversidade no Ártico.', 'enfoca o problema da interrupção da cadeia alimentar, o qual decorre das variações climáticas.', 'ressalta que o aumento da temperatura decorrente de mudanças climáticas permite o surgimento de novas espécies.', 'mostra a importância das características das zonas frias para a manutenção de outros biomas na Terra.', 'sem_imagem.png', NULL, NULL, '', '', NULL, '', '', NULL, NULL, 1),
(21, 1743, '(Enem 2010) O volume de matéria-prima recuperado pela reciclagem do lixo está muito abaixo das necessidades da indústria. No entanto, mais que uma forma de responder ao aumento da demanda industrial por matérias-primas e energia, a reciclagem é uma forma de reintroduzir o lixo no processo industrial. A prática abordada no texto corresponde, no contexto global, a uma situação de sustentabilidade que', 'reduz a utilização de matérias-primas nas indústrias de bens de consumo.', 'reduz o buraco na camada de ozônio nos distritos industriais.', 'ameniza os efeitos das chuvas ácidas nos polos petroquímicos.', 'diminui os efeitos da poluição atmosférica das indústrias siderúrgicas.', 'sem_imagem.png', NULL, NULL, '', '', NULL, '', '', NULL, NULL, 1),
(21, 1744, '(Enem 2012) A sociedade em movimento tem gestado algumas alternativas. Surgem novas experiências de luta no campo, nas quais os movimentos sociais têm buscado formas para permanecer na terra, afirmando sua territorialidade. Estes novos sujeitos sociais, de que são exemplo os seringueiros no Acre e as quebradeiras de coco no Maranhão, Pará, Tocantins e Piauí, têm lutado por seu reconhecimento, chegando em certos casos a obter mudanças na legislação. De acordo com o debate apresentado no texto,  a organização social e política dos seringueiros busca', 'a efetivação de políticas públicas para a preservação das florestas como condição de garantia de sustentabilidade.', 'a implementação de estratégias de geração de emprego e renda apoiadas na automação produtiva de ponta.', 'a distribuição de grandes extensões de terra com financiamentos voltados à produção agroindustrial em larga escala.', 'o estímulo à implantação generalizada de indústrias do setor de papel e celulose focadas na Amazônia.', 'sem_imagem.png', NULL, NULL, '', '', NULL, '', '', NULL, NULL, 1),
(21, 1745, '(Enem 2018) O Decreto Federal n. 7.390/2010, que regulamenta a Lei da Política Nacional sobre Mudança do Clima (PNMC) no Brasil, projeta que as emissões nacionais de gases de efeito estufa (GEE) em 2020 serão de 3,236 milhões. Esse mesmo decreto define o compromisso nacional voluntário do Brasil em reduzir as emissões de GEE projetadas para 2020 entre 38,6% e 38,9%. O cumprimento da meta mencionada está condicionada por', 'investir em energias sustentáveis.', 'abdicar das usinas nucleares.', 'explorar reservas do pré-sal.', 'utilizar gás de xisto betuminoso', 'sem_imagem.png', NULL, NULL, '', '', NULL, '', '', NULL, NULL, 1),
