(23, 1749, 'Quem foi Enstein?', 'Foi um físico teórico alemão que desenvolveu a teoria da relatividade geral, um dos pilares da física moderna ao lado da mecânica quântica', 'Foi um psiquiatra alemão.', 'O descobridor do buraco negro do universo.', 'Matemático alemão.', 'T23_perg_1749.peg', NULL, NULL, '', '', NULL, '', '', NULL, NULL, 1),
